+      // Initialize Tippy.js tooltips
+      document.addEventListener('DOMContentLoaded', () => {
+        if (typeof tippy !== 'undefined') {
+          // Initialize tooltips on elements with data-tippy-content
+          tippy('[data-tippy-content]', {
+            theme: 'agent-mail',
+            animation: 'scale',
+            duration: [200, 150],
+            arrow: true,
+            placement: 'top'
+          });
+
+          // Auto-initialize on new elements
+          const observer = new MutationObserver(() => {
+            tippy('[data-tippy-content]:not([data-tippy-initialized])', {
+              theme: 'agent-mail',
+              animation: 'scale',
+              duration: [200, 150],
+              arrow: true,
+              placement: 'top'
+            });
+          });
+
+          observer.observe(document.body, {
+            childList: true,
+            subtree: true
+          });
+        }
+
+        // Stagger animation for list items
+        const staggerElements = document.querySelectorAll('.stagger-item');
+        staggerElements.forEach((el, index) => {
+          el.style.animationDelay = `${index * 0.05}s`;
+        });
+
+        // Animate stat numbers on scroll
+        const observerOptions = {
+          threshold: 0.5,
+          rootMargin: '0px'
+        };
+
+        const statObserver = new IntersectionObserver((entries) => {
+          entries.forEach(entry => {
+            if (entry.isIntersecting && !entry.target.dataset.animated) {
+              const target = entry.target;
+              const finalValue = parseInt(target.textContent);
+              if (!isNaN(finalValue)) {
+                animateValue(target, 0, finalValue, 1000);
+                target.dataset.animated = 'true';
+              }
+            }
+          });
+        }, observerOptions);
+
+        document.querySelectorAll('.stat-number').forEach(el => {
+          statObserver.observe(el);
+        });
+
+        // Smooth scroll to anchors
+        document.querySelectorAll('a[href^="#"]').forEach(anchor => {
+          anchor.addEventListener('click', function (e) {
+            const href = this.getAttribute('href');
+            if (href !== '#' && href !== '#!') {
+              e.preventDefault();
+              const target = document.querySelector(href);
+              if (target) {
+                target.scrollIntoView({
+                  behavior: 'smooth',
+                  block: 'start'
+                });
+              }
+            }
+          });
+        });
+      });
+
+      // Animate number counter
+      function animateValue(element, start, end, duration) {
+        const range = end - start;
+        const increment = range / (duration / 16); // 60fps
+        let current = start;
+
+        const timer = setInterval(() => {
+          current += increment;
+          if ((increment > 0 && current >= end) || (increment < 0 && current <= end)) {
+            current = end;
+            clearInterval(timer);
+          }
+          element.textContent = Math.floor(current).toLocaleString();
+        }, 16);
+      }
+
+      // Add keyboard shortcuts
+      document.addEventListener('keydown', (e) => {
+        // Ctrl/Cmd + K for search
+        if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
+          e.preventDefault();
+          const searchInput = document.querySelector('input[type="search"], input[name="q"]');
+          if (searchInput) {
+            searchInput.focus();
+            searchInput.select();
+          }
+        }
+
+        // Escape to close modals/dropdowns
+        if (e.key === 'Escape') {
+          // Close any open Alpine.js dropdowns
+          window.dispatchEvent(new CustomEvent('close-all-dropdowns'));
+        }
+      });
+
+      // Add visual feedback for copy actions
+      window.copyToClipboard = async function(text, successMessage = 'Copied to clipboard!') {
+        try {
+          await navigator.clipboard.writeText(text);
+          window.showToast(successMessage, 'success', 2000);
+          return true;
+        } catch (err) {
+          window.showToast('Failed to copy', 'error', 2000);
+          return false;
+        }
+      };
+
+      // Relative time formatting helper
+      window.formatRelativeTime = function(dateString) {
+        if (typeof dayjs === 'undefined') return dateString;
+        return dayjs(dateString).fromNow();
+      };
+
+      // Calendar time formatting helper
+      window.formatCalendarTime = function(dateString) {
+        if (typeof dayjs === 'undefined') return dateString;
+        return dayjs(dateString).calendar();
+      };
     </script>

